void s_FillA0DataPacket(u8 cmd)
{


	u8 index=0;
	u8 a0datapacket[67];
	u16 appcs=s_GetEEPSum();
	a0datapacket[index++]=A0_HEAD;

	//s_HJXReadHAP(&a0datapacket[index],T_AddrTable[gHJXHAPInfo.mode],4);
	//index+=4;
	a0datapacket[index++]=gHJXHAPInfo.mode;
	//s_HJXReadHAP(&a0datapacket[index++],T_AddrTable[gHJXHAPInfo.mode],1);
	//s_HJXReadHAP(&a0datapacket[index++],T_AddrTable[gHJXHAPInfo.mode]+1,1);
	//s_HJXReadHAP(&a0datapacket[index++],T_AddrTable[gHJXHAPInfo.mode]+2,1);
	a0datapacket[index++]=(s_HJXReadCurVol()>>10)&0x1F;
	a0datapacket[index++]=cmd;
	a0datapacket[index++]=(s_HJXReadCurVol())&0x1F;
	//s_HJXReadHAP(&a0datapacket[index++],T_AddrTable[gHJXHAPInfo.mode]+3,1);
	s_HJXRead70132K(&a0datapacket[index++],A0_NLEVELADDR,1);
	a0datapacket[index++]=battery_value_to_phone_level()*10;
	a0datapacket[index++]=appcs>>8;
	a0datapacket[index++]=appcs&0xFF;
	printf("appcs:%x",appcs);
	s_HJXRead70132K(&a0datapacket[index],A0_MATERIALNUMBERADDR,4);
	index+=4;

	s_HJXRead70132K(&a0datapacket[index],A0_MODELADDR,16);
	index+=16;

	s_HJXRead70132K(&a0datapacket[index],A0_SERIALNUMBERADDR,16);
	index+=16;

	s_HJXRead70132K(&a0datapacket[index],T_EQUALIZERADDRTable[gHJXHAPInfo.mode],16);
	index+=16;
	a0datapacket[index++]=A0_BT_VERSION;

	s_HJXRead70132K(&a0datapacket[index],A0_HAPVERSIONADDR,2);
	index+=2;

	s_HJXRead70132K(&a0datapacket[index++],A0_HAPHARDVERSIONADDR,1);
	a0datapacket[index++]=gHJXHAPInfo.rightleftflag;
	u8 cs=0;
	for(u8 i=0;i<index;i++)
	{
		cs+=a0datapacket[i];
	}
	a0datapacket[index++]=cs;
	printf_buf(a0datapacket,67);
	s_HJXBleSend(a0datapacket,sizeof(a0datapacket));
}
void s_FillF8datapacket(u16 num)
{
	printf("s_FillF8datapacket\n");
	u8 F8datapacket[265];
	u16 index=0;
	u16 saddr=256*num,eaddr=(num*256)+255;
	F8datapacket[index++]=F8_HEAD;
	u16 appcs=0;


	for(u16 i=0;i<gHJXBleData.len-1;i++)
	{
		appcs+=gHJXBleData.buf[i];
	}
	if((appcs&0xff)==gHJXBleData.buf[gHJXBleData.len-1])
		F8datapacket[index++]=0;
	else
		F8datapacket[index++]=1;
	F8datapacket[index++]=num;
	F8datapacket[index++]=saddr>>8;
	F8datapacket[index++]=saddr&0xFF;
	F8datapacket[index++]=eaddr>>8;
	F8datapacket[index++]=eaddr&0xFF;
//	if(!gHJXHAPInfo.writeflag)
//		s_HJXReadHAP(&F8datapacket[index],saddr,256);
//	else
		s_HJXRead70132K(&F8datapacket[index],saddr,256);
	memcpy(&gHJXEEPPointer[saddr],&F8datapacket[index],256);
	printf_buf(&gHJXEEPPointer[saddr],256);
	index+=256;
	u16 cs=0;
	for(u16 i=0;i<index;i++)
	{
		cs+=F8datapacket[i];
	}
	F8datapacket[index]=cs&0xFF;
	//printf_buf(F8datapacket,sizeof(F8datapacket));
	s_HJXBleSend(F8datapacket,sizeof(F8datapacket));
}
