	s_HJXRead70132K(&a0datapacket[index],T_EQUALIZERADDRTable[gHJXHAPInfo.mode],16);
	index+=16;
	a0datapacket[index++]=A0_BT_VERSION;

	s_HJXRead70132K(&a0datapacket[index],A0_HAPVERSIONADDR,2);
	index+=2;

	s_HJXRead70132K(&a0datapacket[index++],A0_HAPHARDVERSIONADDR,1);
	a0datapacket[index++]=gHJXHAPInfo.rightleftflag;
	// 验配标志判断：读取0x3FDD和0x5FDD，任一地址有非0且非0xFF数据即为已验配
	u8 fitted = 0;
	u8 hearing_aid_buf[33];
	s_HJXRead70132K(hearing_aid_buf, HEARING_AID_ADDR_1, 33);
	for(u8 i=0; i<33; i++)
	{
		if(hearing_aid_buf[i] != 0 && hearing_aid_buf[i] != 0xFF)
		{
			fitted = 1;
			break;
		}
	}
	if(fitted == 0)
	{
		s_HJXRead70132K(hearing_aid_buf, HEARING_AID_ADDR_2, 33);
		for(u8 i=0; i<33; i++)
		{
			if(hearing_aid_buf[i] != 0 && hearing_aid_buf[i] != 0xFF)
			{
				fitted = 1;
				break;
			}
		}
	}
	a0datapacket[index++] = fitted;
	u8 cs=0;
	for(u8 i=0;i<index;i++)
	{
		cs+=a0datapacket[i];
	}
	a0datapacket[index++]=cs;
	printf_buf(a0datapacket,67);
	s_HJXBleSend(a0datapacket, index);
}
